#include <iostream>

class Point {
private:
    int x;
    int y;

public:
    Point() : x(0), y(0) {}
    Point(int x_val, int y_val) : x(x_val), y(y_val) {}
    Point(const Point& other) : x(other.x), y(other.y) {}
    int getX() const { return x; }
    int getY() const { return y; }
    void display() const { std::cout << "Point coordinates: (" << x << ", " << y << ")" << std::endl; }
};

void processPoint(Point p) { p.display(); }

int main() {
    Point p1;
    Point p2(1,2);
    Point p3 = p2;
    processPoint(p2);
    return 0;
}
